import java.math.BigInteger;

public final class FibNative {
  private FibNative() {}

  private static BigInteger[] fibonacciPair(int n) {
    if (n == 0) {
      return new BigInteger[] {BigInteger.ZERO, BigInteger.ONE};
    }

    BigInteger[] pair = fibonacciPair(n / 2);
    BigInteger a = pair[0];
    BigInteger b = pair[1];
    BigInteger c = a.multiply(b.shiftLeft(1).subtract(a));
    BigInteger d = a.multiply(a).add(b.multiply(b));

    if ((n & 1) == 0) {
      return new BigInteger[] {c, d};
    }
    return new BigInteger[] {d, c.add(d)};
  }

  private static int parseInputN(String input) {
    String marker = "\"n\":";
    int start = input.indexOf(marker);
    if (start < 0) {
      return 0;
    }
    start += marker.length();
    while (start < input.length() && Character.isWhitespace(input.charAt(start))) {
      start += 1;
    }
    int end = start;
    while (end < input.length() && Character.isDigit(input.charAt(end))) {
      end += 1;
    }
    if (end == start) {
      return 0;
    }
    return Integer.parseInt(input.substring(start, end));
  }

  public static void main(String[] args) {
    String input = args.length > 0 ? args[0] : "{\"n\":0}";
    int n = Math.max(0, parseInputN(input));
    System.out.println(fibonacciPair(n)[0].toString());
  }
}
